process.scriptContent:
$ErrorActionPreference = 'Stop'
$data = $env:KLEVADEPLOY_DATA_DIR
if ([string]::IsNullOrWhiteSpace($data)) { throw 'KLEVADEPLOY_DATA_DIR mancante' }
$temp = $env:KLEVADEPLOY_TEMP_DIR
if ([string]::IsNullOrWhiteSpace($temp)) { throw 'KLEVADEPLOY_TEMP_DIR mancante' }
$extract = Join-Path $temp 'KlevaDeploy\sql2022_extract'
New-Item -ItemType Directory -Force -Path $extract | Out-Null
$setupInExtract = Join-Path $extract 'setup.exe'
if (Test-Path $setupInExtract) { exit 0 }
$installer = Join-Path $data 'installers\sql-express-2022-sqlpass\SQLEXPR_x64_ENU.exe'
if (!(Test-Path $installer)) { throw ('Installer non trovato: ' + $installer) }
$p = Start-Process -FilePath $installer -ArgumentList @('/q', ('/x:' + $extract)) -Wait -PassThru -WindowStyle Hidden
if ($p.ExitCode -ne 0) { exit $p.ExitCode }
if (!(Test-Path $setupInExtract)) { throw ('setup.exe non trovato in: ' + $extract) }
exit 0

$ErrorActionPreference = 'Stop'
function Test-SqlSaLogin {
  param([string]$Server, [string]$Password)

  $cs = "Server=$Server;User ID=sa;Password=$Password;Database=master;TrustServerCertificate=True;Encrypt=False;Connection Timeout=5"
  $last = $null
  for ($i = 0; $i -lt 30; $i++) {
    try {
      $cn = New-Object System.Data.SqlClient.SqlConnection($cs)
      $cn.Open()
      $cmd = $cn.CreateCommand()
      $cmd.CommandText = 'SELECT 1'
      [void]$cmd.ExecuteScalar()
      $cn.Close()
      return $true
    } catch {
      $last = $_
      Start-Sleep -Seconds 2
    }
  }

  if ($last) { throw $last }
  return $false
}

$saPwd = $env:KLEVADEPLOY_SQLPASS_SA_PASSWORD
if ([string]::IsNullOrWhiteSpace($saPwd)) {
  $saPwd = 'SaSqlPass*01'
  Write-Output 'KLEVADEPLOY_SQLPASS_SA_PASSWORD non impostata: uso password predefinita (SaSqlPass*01).'
}

$server = "$env:COMPUTERNAME\SQLPASS"

$svc = Get-Service -Name 'MSSQL$SQLPASS' -ErrorAction SilentlyContinue
if ($svc) {
  if ($svc.Status -ne 'Running') {
    try { Start-Service -Name 'MSSQL$SQLPASS' -ErrorAction SilentlyContinue } catch { }
  }
  Write-Output 'Istanza SQLPASS gia installata: verifico login sa...'
  if (Test-SqlSaLogin -Server $server -Password $saPwd) {
    Write-Output 'SQLPASS OK'
    exit 0
  }
  throw 'SQLPASS presente ma login sa non valido o istanza non raggiungibile.'
}

$temp = $env:KLEVADEPLOY_TEMP_DIR
if ([string]::IsNullOrWhiteSpace($temp)) { throw 'KLEVADEPLOY_TEMP_DIR mancante' }
$extract = Join-Path $temp 'KlevaDeploy\sql2022_extract'
$setup = Join-Path $extract 'setup.exe'
if (!(Test-Path $setup)) { throw ('setup.exe non trovato in: ' + $extract) }
$args = @(
  '/Q', '/HIDECONSOLE', '/ACTION=Install',
  '/IACCEPTSQLSERVERLICENSETERMS=True',
  '/FEATURES=SQLENGINE',
  '/INSTANCENAME=SQLPASS',
  '/SECURITYMODE=SQL',
  ('/SAPWD="' + $saPwd + '"'),
  '/SQLSYSADMINACCOUNTS="BUILTIN\Administrators"',
  '/TCPENABLED=1', '/NPENABLED=0',
  '/BROWSERSVCSTARTUPTYPE=Automatic',
  '/UPDATEENABLED=0'
)
$roots = @(
  (Join-Path $env:ProgramFiles 'Microsoft SQL Server\160\Setup Bootstrap\Log'),
  (Join-Path ${env:ProgramFiles(x86)} 'Microsoft SQL Server\160\Setup Bootstrap\Log')
) | Where-Object { $_ -and (Test-Path $_) }

Write-Output 'KLEVADEPLOY_PROGRESS: 0'
$start = Get-Date
$p = Start-Process -FilePath $setup -ArgumentList $args -PassThru -WindowStyle Hidden
$lastPercent = 0
$lastDetailLen = -1
$sessionDir = $null
$detailPath = $null

while (-not $p.HasExited) {
  Start-Sleep -Seconds 2

  if (-not $sessionDir) {
    foreach ($r in $roots) {
      $d = Get-ChildItem -Path $r -Directory -ErrorAction SilentlyContinue |
        Where-Object { $_.LastWriteTime -ge $start.AddMinutes(-2) } |
        Sort-Object LastWriteTime -Descending |
        Select-Object -First 1
      if ($d) { $sessionDir = $d.FullName; break }
    }
  }

  if (-not $detailPath -and $sessionDir) {
    $detailTxt = Join-Path $sessionDir 'Detail.txt'
    if (Test-Path $detailTxt) {
      $detailPath = $detailTxt
    } else {
      $cand = Get-ChildItem -Path $sessionDir -File -Filter 'Detail*.txt' -ErrorAction SilentlyContinue |
        Sort-Object LastWriteTime -Descending |
        Select-Object -First 1
      if ($cand) { $detailPath = $cand.FullName }
    }
  }

  if ($detailPath -and (Test-Path $detailPath)) {
    $tail = @()
    try { $tail = Get-Content -Path $detailPath -Tail 200 -ErrorAction SilentlyContinue } catch { $tail = @() }

    $max = $null
    foreach ($line in $tail) {
      if ($line -match '(?i)overall.*?(\d{1,3})\s*%') {
        $v = [int]$Matches[1]
        if ($v -ge 0 -and $v -le 100 -and ($max -eq $null -or $v -gt $max)) { $max = $v }
        continue
      }
      if ($line -match '(?i)progress.*?(\d{1,3})\s*%') {
        $v = [int]$Matches[1]
        if ($v -ge 0 -and $v -le 100 -and ($max -eq $null -or $v -gt $max)) { $max = $v }
        continue
      }
    }

    if ($max -ne $null -and $max -gt $lastPercent) {
      $lastPercent = $max
      Write-Output ('KLEVADEPLOY_PROGRESS: ' + $lastPercent)
    } else {
      try {
        $fi = Get-Item -Path $detailPath -ErrorAction SilentlyContinue
        if ($fi -and $fi.Length -ne $lastDetailLen) {
          $lastDetailLen = $fi.Length
          if ($lastPercent -lt 90) {
            $lastPercent = $lastPercent + 1
            Write-Output ('KLEVADEPLOY_PROGRESS: ' + $lastPercent)
          }
        }
      } catch { }
    }
  }
}

if ($p.ExitCode -eq 0) {
  if ($lastPercent -lt 100) { Write-Output 'KLEVADEPLOY_PROGRESS: 100' }
  Write-Output 'Verifico login sa su SQLPASS...'
  if (Test-SqlSaLogin -Server $server -Password $saPwd) {
    Write-Output 'SQLPASS OK'
    exit 0
  }
  throw 'Installazione completata ma login sa non valido o istanza non raggiungibile.'
} else {
  foreach ($r in $roots) {
    $summary = Get-ChildItem -Path $r -Recurse -File -Filter 'Summary*.txt' -ErrorAction SilentlyContinue |
      Where-Object { $_.Name -ne 'Summary.txt' } |
      Sort-Object LastWriteTime -Descending |
      Select-Object -First 1
    if ($summary) {
      Write-Output ('--- SQL Setup Summary: ' + $summary.FullName + ' ---')
      Get-Content -Path $summary.FullName -ErrorAction SilentlyContinue | Select-Object -Last 200
      break
    }
  }
}
exit $p.ExitCode
